import { useEffect, useState } from 'react';
import Loader from 'react-loaders';
import { Link } from 'react-router-dom';
import AnimatedLetters from '../AnimatedLetters';
import './index.scss';
import LaLigaLogo from '../../assets/images/laliga-logo.png';
const FEATURED_PLAYER_IMAGE = "https://upload.wikimedia.org/wikipedia/commons/2/26/Jude_Bellingham_2022-11-21_1.jpg";

const Home = () => {
    const [letterClass, setLetterClass] = useState('text-animate')
    const nameArray = "Welcome to".split("");
    const jobArray = "LaLiga Zone Fantasy!".split("");
    const featuredPlayer = {
      name: "Jude Bellingham",
      club: "Real Madrid",
      role: "Midfielder",
      nationality: "England",
    };

    useEffect(() => {
        const timerId = setTimeout(() => {
          setLetterClass('text-animate-hover');
        }, 4000);

        return () => {
          clearTimeout(timerId);
        };
      }, []);

    return(
      <>
        <div className = "container home-page">
            <div className="text-zone">
                <h1>
                <img src={LaLigaLogo} alt="LaLiga logo" />
                <br />
                <AnimatedLetters letterClass={letterClass} strArray={nameArray} idx={12} />
                <br /> 
                <AnimatedLetters letterClass={letterClass} strArray={jobArray} idx={15} /> 
                </h1>
                <h2>Your home for everything LaLiga related!</h2>
                <h2>
                  Featured Player: {featuredPlayer.name} ({featuredPlayer.club}) - {featuredPlayer.role}, {featuredPlayer.nationality}
                </h2>
                <img
                  src={FEATURED_PLAYER_IMAGE}
                  alt={`${featuredPlayer.name} profile`}
                  style={{ width: '140px', height: '190px', objectFit: 'cover', borderRadius: '8px', marginTop: '12px' }}
                />
                <Link to="/teams" className="flat-button">GET STARTED</Link>
            </div>
        </div>
        <Loader type="pacman" />
      </>
    )
}

export default Home
